mapper.select:
SELECT f.*, p.project_name, b.building_name FROM elder_floor f LEFT JOIN elder_project p ON f.project_id = p.id LEFT JOIN elder_building b ON b.id = f.building_id WHERE f.del_flag = 0
AND f.project_id IN (
#{id}
)
AND f.project_id = #{data.projectId}
AND f.building_id = #{data.buildingId}
AND f.floor_name LIKE concat(concat('%',#{data.floorName}),'%')
order by f.create_time desc
